// ── Draw events (wall drawing / dragging start+end) ────────────────────
function bindDrawEvents() {
    var drawing = null; // 'wall' | 'erase' | 'dragStart' | 'dragEnd'

    $('#draw_area').off('mousedown').on('mousedown', function(e) {
        if (isSearching) return;
        var coord = View.toGridCoordinate(e.pageX, e.pageY);
        var gx = coord[0], gy = coord[1];

        if (gx === startX && gy === startY) { drawing = 'dragStart'; return; }
        if (gx === endX   && gy === endY)   { drawing = 'dragEnd';   return; }

        if (grid.isWalkableAt(gx, gy)) {
            drawing = 'wall';
            setWalkable(gx, gy, false);
        } else {
            drawing = 'erase';
            setWalkable(gx, gy, true);
        }
    });

    $(window).off('mousemove.sb').on('mousemove.sb', function(e) {
        if (!drawing) return;
        var coord = View.toGridCoordinate(e.pageX, e.pageY);
        var gx = coord[0], gy = coord[1];
        if (gx < 0 || gy < 0 || gx >= grid.width || gy >= grid.height) return;

        if (drawing === 'dragStart' && grid.isWalkableAt(gx, gy) &&
            !(gx === endX && gy === endY)) {
            startX = gx; startY = gy;
            View.setStartPos(gx, gy);
        } else if (drawing === 'dragEnd' && grid.isWalkableAt(gx, gy) &&
                   !(gx === startX && gy === startY)) {
            endX = gx; endY = gy;
            View.setEndPos(gx, gy);
        } else if (drawing === 'wall' && !(gx === startX && gy === startY) &&
                   !(gx === endX && gy === endY)) {
            setWalkable(gx, gy, false);
        } else if (drawing === 'erase') {
            setWalkable(gx, gy, true);
        }
    });

    $(window).off('mouseup.sb').on('mouseup.sb', function() {
        drawing = null;
    });
}

function setWalkable(gx, gy, walkable) {
