function abortSearch() {
    if (animTimer) { clearInterval(animTimer); animTimer = null; }
    isSearching = false;
}

function buildFinder(id) {
    switch (id) {
        case 'AStarFinder':          return new PF.AStarFinder();
        case 'BiAStarFinder':        return new PF.BiAStarFinder();
        case 'BestFirstFinder':      return new PF.BestFirstFinder();
        case 'BiBestFirstFinder':    return new PF.BiBestFirstFinder();
        case 'BreadthFirstFinder':   return new PF.BreadthFirstFinder();
        case 'BiBreadthFirstFinder': return new PF.BiBreadthFirstFinder();
        case 'DijkstraFinder':       return new PF.DijkstraFinder();
        case 'BiDijkstraFinder':     return new PF.BiDijkstraFinder();
        case 'IDAStarFinder':        return new PF.IDAStarFinder({ timeLimit: 10 });
        case 'JumpPointFinder':      return new PF.JumpPointFinder({
            diagonalMovement: PF.DiagonalMovement.IfAtMostOneObstacle
        });
        default: return null;
    }
}

